def parse_nombre(raw):
    toks = raw.split()
    if len(toks) < 3:
        return {'status': 'review', 'raw': raw, 'given': None, 'apellidos': None}
    return {
        'status': 'ok',
        'raw': raw,
        'given': ' '.join(toks[:-2]),
        'apellidos': toks[-2:],
    }
print(parse_nombre('SoloUno'))
print(parse_nombre('Ana María Quispe Huamán'))

def normalize_email(raw):
    s = raw.strip().casefold()
    if ' ' in s or s.count('@') != 1:
        raise ValueError(f'review_error email={raw!r}')
    local, domain = s.split('@')
    if not local or not domain:
        raise ValueError(f'review_error email={raw!r}')
    return s
print('ok', normalize_email('  A@B.COM '))
for bad in ['@b.com', 'a@@b.com', 'a b@c.com']:
    try:
        normalize_email(bad)
    except ValueError as e:
        print('review_error', bad)
print('ok', normalize_email('user+tag@example.com'))

def norm(s):
    return ' '.join(s.strip().split()).casefold()
print(norm('  Juan  PEREZ ') == norm('juan perez'))

def jaccard(a, b):
    ta, tb = set(a.casefold().split()), set(b.casefold().split())
    if not ta and not tb:
        return 1.0
    return round(len(ta & tb) / len(ta | tb), 3)
print(jaccard('Ana María Quispe', 'Ana Quispe Rojas'))

def decide(score):
    if score >= 0.9:
        return 'auto_link_candidate'
    if score >= 0.5:
        return 'review'
    return 'no_link'
for s in [0.95, 0.67, 0.2]:
    print(s, decide(s))
print('0.67 → review con raw y score; no parentesco automático')

def evidence(a, b, score):
    return {'raw_a': a, 'raw_b': b, 'score': score, 'action': 'review' if 0.5 <= score < 0.9 else ('link' if score >= 0.9 else 'drop')}
print(evidence('Ana Quispe', 'Ana Q.', 0.67))
